<?php
namespace App\Services\Finance;use App\Models\{PaymentProviderSecret,User};use Illuminate\Support\Facades\Crypt;class PaymentProviderSecretService{public function setSecret(string $p,string $e,string $k,string $v,User $a):PaymentProviderSecret{abort_if(blank($v),422,'Secret value is required.');return PaymentProviderSecret::updateOrCreate(['provider'=>$p,'environment'=>$e,'key_name'=>$k],['encrypted_value'=>Crypt::encryptString($v),'last_four'=>substr($v,-4),'present'=>true,'created_by_id'=>$a->id,'updated_by_id'=>$a->id]);}public function hasSecret(string $p,string $e,string $k):bool{return PaymentProviderSecret::where(['provider'=>$p,'environment'=>$e,'key_name'=>$k,'present'=>true])->exists();}public function getSecret(string $p,string $e,string $k):?string{$s=PaymentProviderSecret::where(['provider'=>$p,'environment'=>$e,'key_name'=>$k,'present'=>true])->first();return $s?Crypt::decryptString($s->encrypted_value):null;}public function forgetSecret(string $p,string $e,string $k,User $a):void{PaymentProviderSecret::where(['provider'=>$p,'environment'=>$e,'key_name'=>$k])->update(['present'=>false,'encrypted_value'=>Crypt::encryptString('removed'),'last_four'=>null,'updated_by_id'=>$a->id]);}public function readiness(string $p,string $e):array{$x=collect(['client_id','client_secret','subscription_key','webhook_secret'])->mapWithKeys(fn($k)=>[$k=>$this->hasSecret($p,$e,$k)]);return ['present'=>$x->all(),'missing'=>$x->filter(fn($v)=>!$v)->keys()->all(),'ready'=>$x->every(fn($v)=>$v)];}}